import supabase from './supabaseClient'
import React, {useState, useEffect} from 'react'

function DataPointage(){
    const [pointages, setPointages] = useState([]);
    const [loading, setLoading] = useState(true);
    const [searchTerm, setSearchTerm] = useState('');


  useEffect(() => {
    async function fetchPointages() {
      const { data, error } = await supabase
        .from('USER_OF_RUN')
        .select(`
          USERID,
          STARTDATE,
          ENDDATE,
          USERINFO ( Name, TITLE )
          
        `)
        .order('STARTDATE', { ascending: false })
        

      if (error) {
        console.error('Erreur de récupération :', error.message);
      } else {
        setPointages(data);
       
      }
      setLoading(false);
    }

    fetchPointages();
  }, []);

  if (loading) return <p>Chargement des données...</p>;


    return(
        
        <div>
            <input
                type="text"
                placeholder="Rechercher par nom, titre ou ID..."
                value={searchTerm}
                onChange={(e) => setSearchTerm(e.target.value)}
                style={{ marginBottom: '10px', padding: '5px', width: '300px' }}
            />

            <table className='table'>
                    <thead className='t1'>
                        <tr className='champ-name'>
                            <th>ID</th>
                            <th>Nom</th>
                            <th>Titre</th>
                            <th>Heure d'arrivée</th>
                            <th>Heure de départ</th>
                        </tr>
                    </thead>
                    <tbody className='data-table'>
                    {pointages.map((p, index) => (
                        <tr key={index}>
                            <td>{p.USERID}</td>
                            <td>{p.USERINFO?.Name || '—'}</td>
                            <td>{p.USERINFO?.TITLE || '—'}</td>
                            <td>{p.STARTDATE}</td>
                            <td>{p.ENDDATE}</td>
                        </tr>
                    ))}
                    </tbody>
                </table>
        </div>
    )
}

export default DataPointage
